<template>
  <div class="contact-container">
    <b-container fluid="md">
      <b-row>
        <b-col class="col-style">
          <span class="col-subheading">
            Contact
          </span>
          <p>
            Feel free to contact me, whether you have a question or just want to say hello.
            I will try my best to get back to you when I can.
          </p>
          <p>
            Don't forget to leave your contact info so I can get back to you. Cheers!
          </p>
          <b-form @submit.prevent="submit(email)">
            <b-form-textarea
              class="textarea-custom"
              v-model="email.message"
              :placeholder="emailPlaceholder"
              rows="9"
              required
            />
            <div class="d-flex justify-content-end mt-4">
              <b-button
                class="mr-4"
                style="min-width: 5.13rem;"
                type="reset"
                variant="outline-light"
                :disabled="isLoading">
                Clear
              </b-button>
              <b-button
                style="min-width: 5.13rem;"
                type="submit"
                variant="primary"
                :disabled="isLoading">
                <b-spinner v-if="isLoading" style="width: 1.5rem; height: 1.5rem;"/>
                <span v-else>
                  Submit
                </span>
              </b-button>
            </div>
          </b-form>
        </b-col>
      </b-row>
    </b-container>
  </div>
</template>

<script>
import { mapActions, mapGetters } from 'vuex';

export default {
  name: 'Contact',

  data: function () {
    return {
      email: this.initEmailForm(),
    };
  },

  computed: {
    ...mapGetters('contact', ['isLoading']),

    emailPlaceholder: function () {
      return 'Hey Hector,'
        + '\n\nI just wanted to say hello. If you could reach me at john.doe@gmail.com,'
        + ' I would like to talk about xyz.\n\nThanks,\nYour name';
    },
  },

  methods: {
    ...mapActions('contact', ['sendEmail']),

    initEmailForm: function () {
      return {
        message: null,
      };
    },

    submit: function ({ message }) {
      console.log(message);
      this.sendEmail(message)
        .then(() => {
          this.email = this.initEmailForm();
          this.$bvToast.toast('Your message was sent.', {
            title: 'Succeeded',
            variant: 'success',
            autoHideDelay: 7000,
            solid: true,
          });
        })
        .catch(() => {
          this.$bvToast.toast('Message failed to send. Please try again later.', {
            title: 'Failed',
            variant: 'danger',
            autoHideDelay: 7000,
            solid: true,
          });
        });
    },
  },
};
</script>

